import React from 'react';
import { BrowserRouter as Router, Routes, Route, useLocation, useNavigate } from 'react-router-dom';
import PizzaMenu from './components/PizzaMenu';
import Cart from './components/Cart';
import CheckoutForm from './components/CheckoutForm';
import OrderSuccess from './components/OrderSuccess';
import AdminDashboard from './components/AdminDashboard';
import LoginPage from './components/LoginPage';
import VerificationScreen from './components/VerificationScreen';
import OrderHistory from './components/OrderHistory';
import OrderTracker from './components/OrderTracker';

const GOLD   = '#FFC107';
const DARK   = '#1A1A1A';
const MUTED  = '#9ca3af';

// ─── SVG Icon Set ────────────────────────────────────────────────────────────
function IconMenu({ active }) {
  const c = active ? GOLD : MUTED;
  return (
    <svg width="22" height="22" viewBox="0 0 24 24" fill="none"
      stroke={c} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="12" cy="12" r="9" />
      <path d="M8 12c0-2.2 1.8-4 4-4s4 1.8 4 4-1.8 4-4 4" />
      <circle cx="12" cy="12" r="1.5" fill={c} stroke="none" />
    </svg>
  );
}

function IconOrders({ active }) {
  const c = active ? GOLD : MUTED;
  return (
    <svg width="22" height="22" viewBox="0 0 24 24" fill="none"
      stroke={c} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <path d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2" />
      <rect x="9" y="3" width="6" height="4" rx="1" />
      <line x1="9" y1="12" x2="15" y2="12" />
      <line x1="9" y1="16" x2="12" y2="16" />
    </svg>
  );
}

function IconTracker({ active }) {
  const c = active ? GOLD : MUTED;
  return (
    <svg width="22" height="22" viewBox="0 0 24 24" fill="none"
      stroke={c} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <path d="M21 10c0 7-9 13-9 13S3 17 3 10a9 9 0 0118 0z" />
      <circle cx="12" cy="10" r="3" />
    </svg>
  );
}

function IconProfile({ active }) {
  const c = active ? GOLD : MUTED;
  return (
    <svg width="22" height="22" viewBox="0 0 24 24" fill="none"
      stroke={c} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <path d="M20 21v-2a4 4 0 00-4-4H8a4 4 0 00-4 4v2" />
      <circle cx="12" cy="7" r="4" />
    </svg>
  );
}

// ─── Bottom Navigation ────────────────────────────────────────────────────────
const SHOW_NAV_PATHS = ['/', '/history', '/tracker', '/login'];

function BottomNav() {
  const { pathname } = useLocation();
  const navigate     = useNavigate();

  if (!SHOW_NAV_PATHS.includes(pathname)) return null;

  const tabs = [
    { path: '/',        label: 'תפריט',  Icon: IconMenu    },
    { path: '/history', label: 'הזמנות', Icon: IconOrders  },
    { path: '/tracker', label: 'מעקב',   Icon: IconTracker },
    { path: '/login',   label: 'פרופיל', Icon: IconProfile },
  ];

  return (
    <nav
      className="fixed bottom-0 left-0 right-0 bg-white flex z-50"
      style={{ height: 64, borderTop: '1px solid #f0f0f0', boxShadow: '0 -2px 12px rgba(0,0,0,0.06)' }}
    >
      {tabs.map(({ path, label, Icon }) => {
        const active = pathname === path;
        return (
          <button
            key={path}
            onClick={() => navigate(path)}
            className="flex-1 flex flex-col items-center justify-center gap-1 transition-all"
            style={{ border: 'none', background: 'none', cursor: 'pointer' }}
          >
            <Icon active={active} />
            <span
              style={{
                fontSize: 10,
                fontWeight: active ? 700 : 500,
                color: active ? GOLD : MUTED,
                letterSpacing: '0.02em',
              }}
            >
              {label}
            </span>
            {active && (
              <span
                style={{
                  position: 'absolute',
                  bottom: 0,
                  width: 20,
                  height: 2,
                  background: GOLD,
                  borderRadius: '2px 2px 0 0',
                }}
              />
            )}
          </button>
        );
      })}
    </nav>
  );
}

// ─── App Shell ────────────────────────────────────────────────────────────────
function AppContent() {
  return (
    <>
      <Routes>
        <Route path="/"        element={<PizzaMenu />} />
        <Route path="/cart"    element={<Cart />} />
        <Route path="/checkout" element={<CheckoutForm />} />
        <Route path="/success" element={<OrderSuccess />} />
        <Route path="/admin"   element={<AdminDashboard />} />
        <Route path="/login"   element={<LoginPage />} />
        <Route path="/verify"  element={<VerificationScreen />} />
        <Route path="/history" element={<OrderHistory />} />
        <Route path="/tracker" element={<OrderTracker />} />
      </Routes>
      <BottomNav />
    </>
  );
}

export default function App() {
  return (
    <Router>
      <AppContent />
    </Router>
  );
}
